class Solution(object):
    def longestCommonPrefix(self, arr1, arr2):
        # Store all prefixes of arr1 in a set
        prefixes = set()
        for v in arr1:
            s = str(v)
            for l in range(1, len(s)+1):
                prefixes.add(s[:l])
        ans = 0
        for v in arr2:
            s = str(v)
            for l in range(1, len(s)+1):
                if s[:l] in prefixes:
                    ans = max(ans, l)
        return ans
